"use client";

import * as React from "react";
import {
  Banner,
  Button,
  Container,
  Modal,
  ToastProvider,
  TooltipProvider,
  useToast,
} from "@gunjo/ui";

/**
 * Modal announcement banner feature, composed from @gunjo/ui:
 *   - Banner (feedback)  — dismissible top-of-page announcement with a CTA + close button
 *   - Modal  (overlay)   — product-update dialog with title, body, primary + secondary CTAs
 *   - ToastProvider / useToast (feedback) — confirmation toasts
 *
 * `useToast()` must run inside <ToastProvider>, so the interactive UI lives in
 * <Announcement /> and the page component only provides the toast context.
 */
function Announcement() {
  const { showToast } = useToast();

  const [bannerVisible, setBannerVisible] = React.useState(true);
  const [modalOpen, setModalOpen] = React.useState(false);

  // Auto-open the modal once on first load to announce the update.
  React.useEffect(() => {
    setModalOpen(true);
  }, []);

  const dismissBanner = () => {
    setBannerVisible(false);
    showToast("最新の状態です", "info");
  };

  const confirmModal = () => {
    setModalOpen(false);
    showToast("最新の状態になりました。v2 をお楽しみください！", "success");
  };

  return (
    <main className="min-h-screen bg-background text-foreground">
      {bannerVisible ? (
        <Banner
          variant="info"
          onDismiss={dismissBanner}
          dismissLabel="お知らせを閉じる"
          action={
            <Button
              size="sm"
              variant="primary"
              onClick={() => setModalOpen(true)}
            >
              新機能を見る
            </Button>
          }
        >
          v2 が公開されました——より高速なエディター、ダークモード、30以上の新コンポーネント。
        </Banner>
      ) : null}

      <Container className="max-w-2xl py-16">
        <header className="flex flex-col gap-1.5">
          <h1 className="text-2xl font-semibold tracking-tight">
            ワークスペースへようこそ
          </h1>
          <p className="text-sm text-muted-foreground">
            {bannerVisible
              ? "新しいリリースがあります。上のバナーをご確認ください。"
              : "最新の状態です。お知らせはいつでも再表示できます。"}
          </p>
        </header>

        <div className="mt-8 flex flex-wrap gap-3">
          <Button variant="primary" onClick={() => setModalOpen(true)}>
            お知らせを開く
          </Button>
          {!bannerVisible ? (
            <Button variant="outline" onClick={() => setBannerVisible(true)}>
              バナーを再表示
            </Button>
          ) : null}
        </div>
      </Container>

      <Modal
        isOpen={modalOpen}
        onClose={() => setModalOpen(false)}
        title="v2 が登場"
        closeLabel="お知らせを閉じる"
        footer={
          <>
            <Button variant="outline" onClick={() => setModalOpen(false)}>
              あとで
            </Button>
            <Button variant="primary" onClick={confirmModal}>
              確認しました
            </Button>
          </>
        }
      >
        <div className="flex flex-col gap-3 text-sm text-muted-foreground">
          <p>
            大型アップデートをリリースしました。エディターは体感できるほど高速になり、
            ダークモードを標準搭載。さらに30以上の新しいコンポーネントが加わりました。
          </p>
          <p>
            お時間のあるときに、ぜひ触れてみてください。ワークスペースの中身は
            そのままに、使い心地だけが少しよくなっています。
          </p>
        </div>
      </Modal>
    </main>
  );
}

export default function AnnouncePage() {
  // Banner's built-in dismiss button renders a Tooltip but does NOT self-wrap
  // it in a TooltipProvider (Toast does), so a standalone Banner with onDismiss
  // requires an ancestor TooltipProvider — otherwise SSR/prerender throws
  // "`Tooltip` must be used within `TooltipProvider`".
  return (
    <TooltipProvider>
      <ToastProvider>
        <Announcement />
      </ToastProvider>
    </TooltipProvider>
  );
}
